+            .iter()
+            .filter(|k| state.resident.contains_key(k))
+            .count();
+
+        // Count how many scan keys are resident.
+        let scan_resident: usize = scan_keys
+            .iter()
+            .filter(|k| state.resident.contains_key(k))
