+
+        fi.fail_on_read(BlockNumber(5), FaultMode::OneShot);
+
+        // Reading block 5 should fail.
+        let err = fi.read_block(&cx, BlockNumber(5)).unwrap_err();
+        assert!(matches!(err, FfsError::Corruption { .. }));
